import React, { useState, useEffect } from 'react';
import axios from 'axios';
import Review from './Review';
import ReviewForm from './ReviewForm';

function BookDetails({ bookId, onBack, api_url }) {
  const [book, setBook] = useState(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetchBookDetails();
  }, [bookId]);

  const fetchBookDetails = async () => {
    setIsLoading(true);
    setError(null);
    try {
      const response = await axios.get(`${api_url}/books/${bookId}`);
      setBook(response.data);
    } catch (err) {
      setError('Could not fetch book details.');
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleReviewAdded = (newReview) => {
    setBook(prevBook => ({
      ...prevBook,
      reviews: [...prevBook.reviews, newReview],
    }));
  };

  const handleReviewDeleted = (reviewId) => {
    setBook(prevBook => ({
      ...prevBook,
      reviews: prevBook.reviews.filter(review => review.id !== reviewId),
    }));
  };

  const handleReviewEdited = (updatedReview) => {
    setBook(prevBook => ({
      ...prevBook,
      reviews: prevBook.reviews.map(review =>
        review.id === updatedReview.id ? updatedReview : review
      ),
    }));
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-indigo-50 via-white to-purple-50 flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-16 w-16 border-4 border-indigo-500 border-t-transparent mx-auto mb-4"></div>
          <p className="text-xl text-gray-600 font-medium">Loading book details...</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-red-50 via-white to-pink-50 flex items-center justify-center">
        <div className="text-center max-w-md mx-auto p-8">
          <div className="text-6xl mb-4">📚</div>
          <h2 className="text-2xl font-bold text-gray-800 mb-2">Something went wrong</h2>
          <p className="text-gray-600 mb-6">{error}</p>
          <button 
            onClick={onBack}
            className="px-6 py-3 bg-indigo-600 text-white rounded-xl font-semibold hover:bg-indigo-700 transition-all duration-200 transform hover:scale-105 shadow-lg"
          >
            Go Back
          </button>
        </div>
      </div>
    );
  }

  if (!book) return null;

  const getGradientByRating = (rating) => {
    if (rating >= 4.5) return 'from-emerald-400 to-teal-500';
    if (rating >= 4.0) return 'from-blue-400 to-indigo-500';
    if (rating >= 3.5) return 'from-purple-400 to-pink-500';
    return 'from-orange-400 to-red-500';
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-indigo-50 via-white to-purple-50">
      {/* Header */}
      <div className="bg-white shadow-sm border-b border-gray-100">
        <div className="container mx-auto px-6 py-6">
          <button
            onClick={onBack}
            className="inline-flex items-center px-6 py-3 bg-gradient-to-r from-indigo-500 to-purple-600 text-white rounded-xl font-semibold hover:from-indigo-600 hover:to-purple-700 transition-all duration-200 transform hover:scale-105 shadow-lg hover:shadow-xl"
          >
            <svg className="icon-md mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
            </svg>
            Back to Library
          </button>
        </div>
      </div>

      <div className="container mx-auto px-6 py-12">
        {/* Book Header */}
        <div className="bg-white rounded-3xl shadow-xl p-12 mb-12 relative overflow-hidden">
          {/* Background decoration */}
          <div className="absolute top-0 right-0 w-64 h-64 opacity-5 transform rotate-12 translate-x-16 -translate-y-16">
            <div className={`w-full h-full bg-gradient-to-br ${getGradientByRating(book.rating)} rounded-full`}></div>
          </div>

          <div className="relative">
            <div className="flex flex-col lg:flex-row lg:items-center lg:space-x-12">
              {/* Book Icon */}
              <div className={`w-24 h-24 rounded-2xl bg-gradient-to-r ${getGradientByRating(book.rating)} flex items-center justify-center shadow-2xl mb-8 lg:mb-0`}>
                <span className="text-4xl">📖</span>
              </div>

              {/* Book Info */}
              <div className="flex-1">
                <h1 className="text-4xl lg:text-5xl font-bold text-gray-900 mb-4 leading-tight">
                  {book.title}
                </h1>
                <p className="text-2xl text-gray-600 mb-6 font-medium">
                  by <span className="text-gray-800">{book.author}</span>
                </p>

                {/* Rating */}
                <div className="flex items-center space-x-6">
                  <div className="flex items-center space-x-2">
                    <div className="flex items-center space-x-1">
                      {[...Array(5)].map((_, i) => (
                        <span 
                          key={i} 
                          className={`text-2xl ${
                            i < Math.floor(book.rating) 
                              ? 'text-yellow-400' 
                              : i < book.rating 
                              ? 'text-yellow-300' 
                              : 'text-gray-200'
                          }`}
                        >
                          ⭐
                        </span>
                      ))}
                    </div>
                    <span className="text-3xl font-bold text-gray-800 ml-3">{book.rating}</span>
                  </div>
                  <div className="text-gray-500">
                    <span className="text-lg font-medium">{book.reviews.length}</span>
                    <span className="text-sm ml-1">review{book.reviews.length !== 1 ? 's' : ''}</span>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* Reviews Section */}
        <div className="bg-white rounded-3xl shadow-xl p-12">
          <div className="flex items-center justify-between mb-8">
            <h2 className="text-3xl font-bold text-gray-900 flex items-center">
              <span className="text-4xl mr-3">💬</span>
              Reviews
            </h2>
            <div className="text-sm text-gray-500 bg-gray-100 px-4 py-2 rounded-full">
              {book.reviews.length} total
            </div>
          </div>

          {book.reviews.length === 0 ? (
            <div className="text-center py-16">
              <div className="text-8xl mb-6 opacity-20">📝</div>
              <h3 className="text-2xl font-semibold text-gray-800 mb-3">No reviews yet</h3>
              <p className="text-gray-500 text-lg max-w-md mx-auto">
                Be the first to share your thoughts about this book!
              </p>
            </div>
          ) : (
            <div className="space-y-6">
              {book.reviews.map(review => (
                <Review
                  key={review.id}
                  review={review}
                  bookId={book.id}
                  api_url={api_url}
                  onReviewDeleted={handleReviewDeleted}
                  onReviewEdited={handleReviewEdited}
                />
              ))}
            </div>
          )}
        </div>

        {/* Review Form */}
        <div className="mt-8">
          <ReviewForm bookId={book.id} onReviewAdded={handleReviewAdded} api_url={api_url} />
        </div>
      </div>
    </div>
  );
}

export default BookDetails;
